--
-- Target DB: Microsoft SQL Server 2022 Express
-- Database: [demo_utm_AGBM]
-- Objective: Seed the 'Producto' table with 250 high-rotation products for the Mexican market.

-- Best Practices: Ensure atomicity, idempotency, and error handling.
SET NOCOUNT ON;
SET XACT_ABORT ON;

-- Ensure the script operates within the correct database context.
USE [demo_utm_AGBM];
GO

BEGIN TRANSACTION;

BEGIN TRY
    -- 1. CLEANUP PHASE
    -- Use DELETE and RESEED to handle Foreign Key constraints.
    DELETE FROM [dbo].[Producto];
    DBCC CHECKIDENT ('[dbo].[Producto]', RESEED, 0);

    -- 2. DATA INSERTION PHASE
    -- Inserting 250 products.

    -- Batch 1/5: Refrescos, Botanas, Lácteos, Panadería (50 items)

    -- Batch 2/5: Abarrotes, Higiene, Refrescos (50 items)

    -- Batch 3/5: Lácteos, Panadería, Botanas (50 items)

    -- Batch 4/5: Higiene, Abarrotes, Refrescos (50 items)

    -- Batch 5/5: Panadería, Lácteos, Botanas (50 items)

    -- 3. FINALIZATION AND VERIFICATION
    -- Reseed the identity counter to the last inserted value to keep it synchronized.
    DBCC CHECKIDENT ('[dbo].[Producto]', RESEED, 250);

    COMMIT TRANSACTION;
    PRINT 'Transacción completada. 250 productos han sido registrados exitosamente en [dbo].[Producto].';

END TRY
BEGIN CATCH
    -- If an error occurs, roll back the entire transaction.
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;

    -- Rethrow the error to the client.
    DECLARE @ErrorMessage NVARCHAR(4000);
    DECLARE @ErrorSeverity INT;
    DECLARE @ErrorState INT;

    SELECT 
        @ErrorMessage = ERROR_MESSAGE(),
        @ErrorSeverity = ERROR_SEVERITY(),
        @ErrorState = ERROR_STATE();

    RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);
    PRINT 'Error durante la ejecución. La transacción ha sido revertida.';
END CATCH;
GO
